// ==UserScript==
// @name         geobg
// @namespace    local.geoduels.custom-main-menu-background
// @version      0.2.0
// @description  Adds a tiny local image-bubble picker for the GeoDuels main menu background.
// @author       fketa
// @match        https://geoduels.io/*
// @match        https://www.geoduels.io/*
// @run-at       document-start
// @inject-into  page
// @grant        none
// ==/UserScript==

(function () {
  "use strict";

  var STORAGE_KEY = "geoduels.mainMenuBackground.v1";
  var ROOT_ID = "geoduels-main-menu-background-root";
  var STYLE_ID = ROOT_ID + "-style";
  var FILE_INPUT_ID = ROOT_ID + "-file";
  var DEFAULT_BACKGROUND_URL = "/bg2.v1.jpg";
  var TARGET_BACKGROUND_FRAGMENT = "bg2.v1.jpg";
  var BUBBLE_IMAGE_DATA_URL = "data:image/jpeg;base64,";
  var BUBBLE_SIZE = 54;
  var BUBBLE_MARGIN = 10;
  var MAX_IMAGE_DIMENSION = 2560;
  var MAX_DATA_URL_LENGTH = 4 * 1024 * 1024;
  var IMAGE_QUALITY = 0.9;
  var FIT_OPTIONS = { cover: true, contain: true };
  var POSITION_OPTIONS = {
    center: true,
    "center top": true,
    "center bottom": true,
    "left center": true,
    "right center": true
  };

  var settings = readSettings();
  var domObserver = null;
  var scanQueued = false;
  var dragState = null;

  window.__geoduelsMainMenuBackground = {
    getSettings: function () {
      return cloneSettings(settings);
    },
    setImageUrl: function (url) {
      var next = normalizeImageUrl(url);
      if (!next) throw new Error("Use an http(s), local path, or data:image URL.");
      saveSettings({ imageUrl: next, source: "console" });
      return true;
    },
    setFit: function (fit) {
      if (!FIT_OPTIONS[fit]) throw new Error("Fit must be cover or contain.");
      saveSettings({ fit: fit });
      return true;
    },
    setPosition: function (position) {
      if (!POSITION_OPTIONS[position]) throw new Error("Unsupported position.");
      saveSettings({ position: position });
      return true;
    },
    clear: function () {
      saveSettings({ imageUrl: "", source: "" });
      return true;
    },
    open: function () {
      openFilePicker();
      return true;
    },
    close: function () {
      return true;
    },
    rescan: function () {
      scanTargets();
      return true;
    }
  };

  installStyle();
  applySettings();
  startWhenReady();

  function defaultSettings() {
    return {
      imageUrl: "",
      source: "",
      fit: "cover",
      position: "center",
      bubbleLeft: null,
      bubbleTop: null,
      updatedAt: 0
    };
  }

  function readSettings() {
    var defaults = defaultSettings();

    try {
      var parsed = JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}");

      return {
        imageUrl: typeof parsed.imageUrl === "string" ? parsed.imageUrl : defaults.imageUrl,
        source: typeof parsed.source === "string" ? parsed.source : defaults.source,
        fit: FIT_OPTIONS[parsed.fit] ? parsed.fit : defaults.fit,
        position: POSITION_OPTIONS[parsed.position] ? parsed.position : defaults.position,
        bubbleLeft: typeof parsed.bubbleLeft === "number" ? parsed.bubbleLeft : defaults.bubbleLeft,
        bubbleTop: typeof parsed.bubbleTop === "number" ? parsed.bubbleTop : defaults.bubbleTop,
        updatedAt: typeof parsed.updatedAt === "number" ? parsed.updatedAt : defaults.updatedAt
      };
    } catch (error) {
      console.warn("[geoduels-menu-bg] could not read settings", error);
      return defaults;
    }
  }

  function cloneSettings(value) {
    return {
      imageUrl: value.imageUrl,
      source: value.source,
      fit: value.fit,
      position: value.position,
      bubbleLeft: value.bubbleLeft,
      bubbleTop: value.bubbleTop,
      updatedAt: value.updatedAt
    };
  }

  function saveSettings(patch) {
    settings = {
      imageUrl: typeof patch.imageUrl === "string" ? patch.imageUrl : settings.imageUrl,
      source: typeof patch.source === "string" ? patch.source : settings.source,
      fit: FIT_OPTIONS[patch.fit] ? patch.fit : settings.fit,
      position: POSITION_OPTIONS[patch.position] ? patch.position : settings.position,
      bubbleLeft: typeof patch.bubbleLeft === "number" ? patch.bubbleLeft : settings.bubbleLeft,
      bubbleTop: typeof patch.bubbleTop === "number" ? patch.bubbleTop : settings.bubbleTop,
      updatedAt: Date.now()
    };

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
    } catch (error) {
      console.warn("[geoduels-menu-bg] localStorage save failed", error);
      return false;
    }

    applySettings();
    refreshBubble();
    window.dispatchEvent(
      new CustomEvent("geoduels:main-menu-background", {
        detail: {
          imageUrl: settings.imageUrl,
          fit: settings.fit,
          position: settings.position
        }
      })
    );
    return true;
  }

  function currentImageUrl() {
    return settings.imageUrl || DEFAULT_BACKGROUND_URL;
  }

  function applySettings() {
    var root = document.documentElement;
    if (!root) return;

    root.style.setProperty("--geoduels-menu-bg-image", cssUrlValue(currentImageUrl()));
    root.style.setProperty("--geoduels-menu-bg-fit", settings.fit || "cover");
    root.style.setProperty("--geoduels-menu-bg-position", settings.position || "center");

    if (settings.imageUrl) {
      root.classList.add("geoduels-custom-main-menu-bg");
    } else {
      root.classList.remove("geoduels-custom-main-menu-bg");
    }

    queueTargetScan();
  }

  function cssUrlValue(url) {
    return 'url("' + String(url).replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/[\n\r]/g, "") + '")';
  }

  function normalizeImageUrl(raw) {
    var value = String(raw || "").trim();
    if (!value) return "";

    if (/^data:image\/(?:png|jpe?g|gif|webp);base64,/i.test(value)) return value;
    if (/^data:image\/svg\+xml(?:;[^,]*)?,/i.test(value)) return value;

    try {
      var url = new URL(value, location.href);
      if (url.protocol !== "http:" && url.protocol !== "https:") return "";
      return url.toString();
    } catch (error) {
      return "";
    }
  }

  function startWhenReady() {
    if (document.readyState === "loading") {
      document.addEventListener("DOMContentLoaded", start);
    } else {
      start();
    }

    document.addEventListener("keydown", function (event) {
      if (!event.ctrlKey || !event.shiftKey || event.code !== "KeyB") return;
      if (isTypingTarget(event.target)) return;
      event.preventDefault();
      openFilePicker();
    });

    window.addEventListener("resize", refreshBubble);
  }

  function start() {
    installStyle();
    buildBubble();
    scanTargets();
    observeDom();
  }

  function observeDom() {
    if (domObserver || !document.body) return;

    domObserver = new MutationObserver(function (mutations) {
      for (var i = 0; i < mutations.length; i += 1) {
        if (mutations[i].type === "childList" || mutations[i].attributeName === "style") {
          queueTargetScan();
          return;
        }
      }
    });

    domObserver.observe(document.body, {
      childList: true,
      subtree: true,
      attributes: true,
      attributeFilter: ["style"]
    });
  }

  function queueTargetScan() {
    if (scanQueued) return;
    scanQueued = true;
    setTimeout(function () {
      scanQueued = false;
      scanTargets();
    }, 40);
  }

  function scanTargets() {
    if (!document.body) return;

    var elements = document.querySelectorAll("[style]");

    for (var i = 0; i < elements.length; i += 1) {
      var element = elements[i];
      var styleText = element.getAttribute("style") || "";
      var inlineBackground = element.style && element.style.backgroundImage ? element.style.backgroundImage : "";

      if (
        styleText.indexOf(TARGET_BACKGROUND_FRAGMENT) !== -1 ||
        inlineBackground.indexOf(TARGET_BACKGROUND_FRAGMENT) !== -1
      ) {
        element.setAttribute("data-geoduels-menu-bg-target", "true");
      }
    }
  }

  function installStyle() {
    if (document.getElementById(STYLE_ID)) return;

    var style = document.createElement("style");
    style.id = STYLE_ID;
    style.textContent = [
      "html.geoduels-custom-main-menu-bg [data-geoduels-menu-bg-target='true'] {",
      "  background-image: linear-gradient(rgba(18,56,41,.4), rgba(0,0,0,.9)), var(--geoduels-menu-bg-image) !important;",
      "  background-position: var(--geoduels-menu-bg-position, center) !important;",
      "  background-repeat: no-repeat !important;",
      "  background-size: var(--geoduels-menu-bg-fit, cover) !important;",
      "}",
      "#" + ROOT_ID + " {",
      "  position: fixed;",
      "  z-index: 2147483647;",
      "  width: " + BUBBLE_SIZE + "px;",
      "  height: " + BUBBLE_SIZE + "px;",
      "}",
      "#" + ROOT_ID + " * { box-sizing: border-box; }",
      "#" + ROOT_ID + " .geoduels-menu-bg-bubble {",
      "  display: block;",
      "  width: " + BUBBLE_SIZE + "px;",
      "  height: " + BUBBLE_SIZE + "px;",
      "  padding: 0;",
      "  border: 2px solid rgba(255,255,255,.8);",
      "  border-radius: 999px;",
      "  background-color: #07131c;",
      "  background-image: var(--geoduels-menu-bg-bubble-image);",
      "  background-position: center;",
      "  background-repeat: no-repeat;",
      "  background-size: cover;",
      "  box-shadow: 0 10px 24px rgba(0,0,0,.42);",
      "  cursor: grab;",
      "  overflow: hidden;",
      "}",
      "#" + ROOT_ID + " .geoduels-menu-bg-bubble:focus-visible { outline: 3px solid rgba(42,209,143,.95); outline-offset: 3px; }",
      "#" + ROOT_ID + "[data-dragging='true'] .geoduels-menu-bg-bubble {",
      "  cursor: grabbing;",
      "  transform: scale(1.05);",
      "}",
      "#" + ROOT_ID + " input { display: none; }"
    ].join("\n");

    (document.head || document.documentElement).appendChild(style);
  }

  function buildBubble() {
    if (!document.body || document.getElementById(ROOT_ID)) return;

    var root = document.createElement("div");
    root.id = ROOT_ID;
    root.style.setProperty("--geoduels-menu-bg-bubble-image", cssUrlValue(BUBBLE_IMAGE_DATA_URL));

    var button = document.createElement("button");
    button.type = "button";
    button.className = "geoduels-menu-bg-bubble";
    button.setAttribute("aria-label", "Choose GeoDuels main menu background");
    button.addEventListener("pointerdown", startDrag);

    var fileInput = document.createElement("input");
    fileInput.id = FILE_INPUT_ID;
    fileInput.type = "file";
    fileInput.accept = "image/png,image/jpeg,image/webp,image/gif,image/svg+xml";
    fileInput.addEventListener("change", function () {
      var file = fileInput.files && fileInput.files[0];
      fileInput.value = "";
      if (file) handleFile(file);
    });

    root.appendChild(button);
    root.appendChild(fileInput);
    document.body.appendChild(root);
    refreshBubble();
  }

  function refreshBubble() {
    var root = document.getElementById(ROOT_ID);
    if (!root) return;

    root.style.setProperty("--geoduels-menu-bg-bubble-image", cssUrlValue(BUBBLE_IMAGE_DATA_URL));

    var position = getBubblePosition();
    root.style.left = position.left + "px";
    root.style.top = position.top + "px";
  }

  function getBubblePosition() {
    var defaultLeft = Math.max(BUBBLE_MARGIN, window.innerWidth - BUBBLE_SIZE - BUBBLE_MARGIN);
    var defaultTop = Math.max(BUBBLE_MARGIN, window.innerHeight - BUBBLE_SIZE - BUBBLE_MARGIN);

    return clampBubblePosition({
      left: typeof settings.bubbleLeft === "number" ? settings.bubbleLeft : defaultLeft,
      top: typeof settings.bubbleTop === "number" ? settings.bubbleTop : defaultTop
    });
  }

  function clampBubblePosition(position) {
    var maxLeft = Math.max(BUBBLE_MARGIN, window.innerWidth - BUBBLE_SIZE - BUBBLE_MARGIN);
    var maxTop = Math.max(BUBBLE_MARGIN, window.innerHeight - BUBBLE_SIZE - BUBBLE_MARGIN);

    return {
      left: clampNumber(position.left, BUBBLE_MARGIN, maxLeft),
      top: clampNumber(position.top, BUBBLE_MARGIN, maxTop)
    };
  }

  function clampNumber(value, min, max) {
    return Math.min(max, Math.max(min, Number.isFinite(value) ? value : min));
  }

  function startDrag(event) {
    if (event.button !== 0) return;

    var root = document.getElementById(ROOT_ID);
    if (!root) return;

    event.preventDefault();
    var position = getBubblePosition();

    dragState = {
      startX: event.clientX,
      startY: event.clientY,
      left: position.left,
      top: position.top,
      moved: false
    };

    root.setAttribute("data-dragging", "true");

    if (event.currentTarget && event.currentTarget.setPointerCapture) {
      try {
        event.currentTarget.setPointerCapture(event.pointerId);
      } catch (error) {
        // Browsers can reject capture after a very fast pointer release.
      }
    }

    window.addEventListener("pointermove", moveDrag);
    window.addEventListener("pointerup", endDrag, { once: true });
  }

  function moveDrag(event) {
    if (!dragState) return;

    var root = document.getElementById(ROOT_ID);
    if (!root) return;

    var dx = event.clientX - dragState.startX;
    var dy = event.clientY - dragState.startY;

    if (Math.abs(dx) + Math.abs(dy) > 4) {
      dragState.moved = true;
    }

    var position = clampBubblePosition({
      left: dragState.left + dx,
      top: dragState.top + dy
    });

    root.style.left = position.left + "px";
    root.style.top = position.top + "px";
    dragState.currentLeft = position.left;
    dragState.currentTop = position.top;
  }

  function endDrag() {
    if (!dragState) return;

    window.removeEventListener("pointermove", moveDrag);

    var root = document.getElementById(ROOT_ID);
    if (root) root.removeAttribute("data-dragging");

    if (dragState.moved) {
      saveSettings({
        bubbleLeft: typeof dragState.currentLeft === "number" ? dragState.currentLeft : dragState.left,
        bubbleTop: typeof dragState.currentTop === "number" ? dragState.currentTop : dragState.top
      });
    } else {
      openFilePicker();
    }

    dragState = null;
  }

  function openFilePicker() {
    var input = document.getElementById(FILE_INPUT_ID);
    if (input) input.click();
  }

  function handleFile(file) {
    if (!file || !/^image\//i.test(file.type)) {
      console.warn("[geodih-menu-bg] choose an image file");
      return;
    }

    readFileAsDataURL(file)
      .then(function (dataUrl) {
        return prepareImageDataUrl(dataUrl, file.type);
      })
      .then(function (dataUrl) {
        if (dataUrl.length > MAX_DATA_URL_LENGTH) {
          throw new Error("Image is still too large. Use the console API with an image URL instead.");
        }
        saveSettings({ imageUrl: dataUrl, source: "upload" });
      })
      .catch(function (error) {
        console.warn("[geodih-menu-bg] upload failed", error);
      });
  }

  function readFileAsDataURL(file) {
    return new Promise(function (resolve, reject) {
      var reader = new FileReader();
      reader.onload = function () {
        resolve(String(reader.result || ""));
      };
      reader.onerror = function () {
        reject(new Error("Could not read image."));
      };
      reader.readAsDataURL(file);
    });
  }

  function prepareImageDataUrl(dataUrl, mimeType) {
    if (/image\/svg\+xml/i.test(mimeType) || /^data:image\/gif/i.test(dataUrl)) {
      return Promise.resolve(dataUrl);
    }

    return new Promise(function (resolve, reject) {
      var image = new Image();
      image.onload = function () {
        var width = image.naturalWidth || image.width;
        var height = image.naturalHeight || image.height;
        if (!width || !height) {
          reject(new Error("Could not decode image."));
          return;
        }

        var scale = Math.min(1, MAX_IMAGE_DIMENSION / Math.max(width, height));
        var canvas = document.createElement("canvas");
        canvas.width = Math.max(1, Math.round(width * scale));
        canvas.height = Math.max(1, Math.round(height * scale));

        var context = canvas.getContext("2d");
        if (!context) {
          reject(new Error("Could not resize image."));
          return;
        }

        context.drawImage(image, 0, 0, canvas.width, canvas.height);

        var quality = IMAGE_QUALITY;
        var output = canvas.toDataURL("image/jpeg", quality);
        while (output.length > MAX_DATA_URL_LENGTH && quality > 0.6) {
          quality = Math.round((quality - 0.08) * 100) / 100;
          output = canvas.toDataURL("image/jpeg", quality);
        }

        resolve(output);
      };
      image.onerror = function () {
        reject(new Error("Could not decode image."));
      };
      image.src = dataUrl;
    });
  }

  function isTypingTarget(target) {
    if (!target || !target.tagName) return false;
    var tagName = target.tagName;
    return tagName === "INPUT" || tagName === "TEXTAREA" || tagName === "SELECT" || target.isContentEditable;
  }
})();
